import{_ as a,a as n,b as i,c as l,d as r,e as t}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as d,o as s,c as o,a2 as p}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"IP Konumlandırma ve Kullanıcı Yönetimi","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Other/ip-geolocation-and-user-management.md","filePath":"tr-TR/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),u={name:"tr-TR/Other/ip-geolocation-and-user-management.md"};function m(k,e,y,c,g,h){return s(),o("div",null,[...e[0]||(e[0]=[p('<h1 id="ip-konumlandırma-ve-kullanıcı-yonetimi" tabindex="-1">IP Konumlandırma ve Kullanıcı Yönetimi <a class="header-anchor" href="#ip-konumlandırma-ve-kullanıcı-yonetimi" aria-label="Permalink to &quot;IP Konumlandırma ve Kullanıcı Yönetimi&quot;">​</a></h1><p>IP geolocation; yükleyici kayıtları, giriş cihazları ve benzeri günlüklerdeki IP adreslerini yaklaşık konumlara dönüştürür.</p><p>Yapılandırıldıktan sonra yönetim paneli yükleme ve erişim kaynaklarını daha anlaşılır şekilde gösterebilir. User Management ayrıca şüpheli IP adresleri için yükleme erişimini engellemenizi veya geri açmanızı sağlar.</p><h2 id="nereden-yapılandırılır" tabindex="-1">Nereden Yapılandırılır? <a class="header-anchor" href="#nereden-yapılandırılır" aria-label="Permalink to &quot;Nereden Yapılandırılır?&quot;">​</a></h2><p>Şurayı açın:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+a+`" alt="IP geolocation" loading="lazy"></p><h2 id="kullanılabilir-ayarlar" tabindex="-1">Kullanılabilir Ayarlar <a class="header-anchor" href="#kullanılabilir-ayarlar" aria-label="Permalink to &quot;Kullanılabilir Ayarlar&quot;">​</a></h2><p>Yeni IP geolocation akışı tek bir harita servisine bağlı kalmak yerine birden fazla kaynağı destekler.</p><table tabindex="0"><thead><tr><th>Ayar</th><th>Amaç</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>English, Simplified Chinese, Japanese, French gibi görüntüleme dilini seçer.</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind GeoLite Web Service için MaxMind account ID.</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key.</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key. Çin adresleri ve ana kara Çin IP&#39;leri için kullanışlıdır.</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key. Çok dilli IP konumlandırmayı destekler.</td></tr></tbody></table><p>Yalnızca ihtiyacınız olan servisleri doldurun. Her alanı yapılandırmanız gerekmez.</p><p>Hiç anahtar girilmezse ImgBed yerleşik ücretsiz kaynakları denemeye devam eder; ancak kararlılık, dil desteği ve hassasiyet kendi yapılandırdığınız bir servise göre daha düşük olabilir.</p><h2 id="onerilen-secimler" tabindex="-1">Önerilen Seçimler <a class="header-anchor" href="#onerilen-secimler" aria-label="Permalink to &quot;Önerilen Seçimler&quot;">​</a></h2><p>Ağırlıklı olarak Çin adreslerine ihtiyacınız varsa:</p><ol><li>IP geolocation language değerini Simplified Chinese yapın.</li><li>Tencent Map Key yapılandırın.</li><li>İsteğe bağlı olarak MaxMind veya ipapi fallback sources ekleyin.</li></ol><p>İngilizce veya çok dilli adreslere ihtiyacınız varsa:</p><ol><li>İhtiyacınız olan dili seçin.</li><li>MaxMind Account ID ve License Key yapılandırın.</li><li>Daha iyi çok dilli sonuçlar gerekiyorsa ipapi Key ekleyin.</li></ol><h2 id="maxmind-kurulumu" tabindex="-1">MaxMind Kurulumu <a class="header-anchor" href="#maxmind-kurulumu" aria-label="Permalink to &quot;MaxMind Kurulumu&quot;">​</a></h2><p>MaxMind şunları ister:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Account ID değerini MaxMind dashboard içinde bulun ve License Keys sayfasından License Key oluşturun.</p><p><img src="`+n+'" alt="MaxMind key yapılandırması" loading="lazy"></p><p>Oluşturduktan sonra Account ID ve License Key değerlerini ImgBed&#39;e yapıştırıp kaydedin.</p><p>MaxMind ücretsiz planı günlük kullanım için uygundur, ancak request limits vardır. Kota aşılırsa ImgBed diğer kullanılabilir kaynakları denemeye devam eder.</p><h2 id="ipapi-kurulumu" tabindex="-1">ipapi Kurulumu <a class="header-anchor" href="#ipapi-kurulumu" aria-label="Permalink to &quot;ipapi Kurulumu&quot;">​</a></h2><p>ipapi bir APILayer API Key kullanır.</p><p>ipapi konsolunu açın ve orada gösterilen API Key değerini kopyalayın.</p><p><img src="'+i+'" alt="ipapi yapılandırması" loading="lazy"></p><p>ImgBed&#39;deki <code>ipapi Key</code> alanına yapıştırıp kaydedin.</p><p>ipapi çok dilli IP konumlandırmayı destekler ve adresleri seçili dilde göstermek istediğinizde kullanışlıdır. Ücretsiz planında da request limits vardır. Kota biterse ImgBed diğer kullanılabilir kaynakları denemeye devam eder.</p><h2 id="tencent-map-key-kurulumu" tabindex="-1">Tencent Map Key Kurulumu <a class="header-anchor" href="#tencent-map-key-kurulumu" aria-label="Permalink to &quot;Tencent Map Key Kurulumu&quot;">​</a></h2><p>Tencent Map Key, özellikle ana kara Çin IP&#39;leri için Çin adreslerinde kullanışlıdır.</p><p>Tencent Location Service içinde key oluştururken şunu etkinleştirin:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>Oluşturduktan sonra key değerini <code>Tencent Map Key</code> alanına yapıştırıp kaydedin.</p><p>Yalnızca temel Çin IP konumlandırması gerekiyorsa Tencent Map Key başlamak için yeterlidir.</p><h2 id="user-management-icinde-neye-bakılır" tabindex="-1">User Management İçinde Neye Bakılır? <a class="header-anchor" href="#user-management-icinde-neye-bakılır" aria-label="Permalink to &quot;User Management İçinde Neye Bakılır?&quot;">​</a></h2><p>User Management, yönetim panelinin üst kısmından açılır.</p><p><img src="'+l+'" alt="User management" loading="lazy"></p><p>User Management yükleme etkinliğini IP&#39;ye göre gösterir:</p><table tabindex="0"><thead><tr><th>Alan</th><th>Açıklama</th></tr></thead><tbody><tr><td>IP source</td><td>Yükleyici kaynak IP adresi.</td></tr><tr><td>Address</td><td>IP&#39;den çözümlenen yaklaşık konum.</td></tr><tr><td>Total upload size</td><td>Bu IP tarafından yüklenen toplam dosya boyutu.</td></tr><tr><td>Upload count</td><td>Bu IP&#39;den yapılan yükleme sayısı.</td></tr><tr><td>Upload allowed</td><td>Açık ise yüklemeler serbesttir. Kapalı ise yüklemeler engellenir.</td></tr></tbody></table><p>Bu IP&#39;nin yüklediği dosya listesini açmak için soldaki oka tıklayın.</p><p>Dosya listesi file name, preview, file size, moderation result, file status ve upload time gösterir. Yüklemeler şüpheli görünüyorsa önce IP&#39;yi genişletin, dosyaları inceleyin, sonra sonraki yüklemeleri engelleyip engellemeyeceğinize karar verin.</p><p>Bir IP şüpheliyse <code>Upload allowed</code> kapatın. Bu IP&#39;den gelecekteki yüklemeler engellenir.</p><h2 id="arama-sıralama-ve-gelismis-filtreler" tabindex="-1">Arama, Sıralama ve Gelişmiş Filtreler <a class="header-anchor" href="#arama-sıralama-ve-gelismis-filtreler" aria-label="Permalink to &quot;Arama, Sıralama ve Gelişmiş Filtreler&quot;">​</a></h2><p>User Management üst kısmında IP source veya address ile arama yapabilirsiniz.</p><p>Son yükleyicileri, yüksek sıklıkta yükleyenleri veya yüksek kullanım yapan IP&#39;leri bulmak için time, upload count veya total upload size değerlerine göre sıralayın.</p><p>Daha derin inceleme için advanced filters açın.</p><p><img src="'+r+'" alt="Gelişmiş filtreler" loading="lazy"></p><p>Advanced filters şunları destekler:</p><table tabindex="0"><thead><tr><th>Filtre</th><th>Kullanım</th></tr></thead><tbody><tr><td>Time range</td><td>Seçilen dönemde dosya yükleyen IP&#39;leri gösterir.</td></tr><tr><td>Access status</td><td>Normal, blocked ve benzeri durumlara göre filtreler.</td></tr><tr><td>Allow/block list</td><td>Allowlist, blocklist veya unset durumuna göre filtreler.</td></tr><tr><td>File type</td><td>Images, videos, audio, documents, code veya diğer dosyaları yükleyen IP&#39;leri gösterir.</td></tr><tr><td>File size</td><td>Yüklenen dosya boyutu aralığına göre filtreler.</td></tr><tr><td>Age rating</td><td>Unset, General, R12+, R16+, R18 ve benzeri derecelere göre filtreler.</td></tr><tr><td>File status</td><td>Anormal dosyaları incelemek için geçerli dosya durumuna göre filtreler.</td></tr></tbody></table><p>Uygulamak için <code>Apply Filters</code> düğmesine tıklayın. Tüm veriye dönmek için <code>Reset</code> kullanın.</p><h2 id="mobil-gorunum" tabindex="-1">Mobil Görünüm <a class="header-anchor" href="#mobil-gorunum" aria-label="Permalink to &quot;Mobil Görünüm&quot;">​</a></h2><p>Mobilde User Management kart düzenine geçer.</p><p><img src="'+t+`" alt="Mobil user management" loading="lazy"></p><p>Her kart IP, address, total upload size, upload count ve upload allowed anahtarını gösterir. Yatay tablo kaydırmadan kullanıcıları yönetebilirsiniz.</p><h2 id="konum-yanlıs-gorunuyorsa" tabindex="-1">Konum Yanlış Görünüyorsa <a class="header-anchor" href="#konum-yanlıs-gorunuyorsa" aria-label="Permalink to &quot;Konum Yanlış Görünüyorsa&quot;">​</a></h2><p>IP geolocation yaklaşık sonuç verir. Sokak düzeyinde kesin adres değildir.</p><p>Kullanıcı proxy, data center, cloud server veya cross-border network arkasındaysa gösterilen konum gerçek konumdan farklı olabilir.</p><p>Bu özelliği yaklaşık kaynağı anlamak, anormal yüklemeleri bulmak ve engelleme kararlarına yardımcı olmak için kullanın. Kesin takip yöntemi olarak değerlendirmeyin.</p><h2 id="yaygın-durumlar" tabindex="-1">Yaygın Durumlar <a class="header-anchor" href="#yaygın-durumlar" aria-label="Permalink to &quot;Yaygın Durumlar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Durum</th><th>Anlamı</th></tr></thead><tbody><tr><td>Address boş</td><td>IP henüz çözümlenmemiş olabilir veya geçerli kaynak geçici olarak kullanılamıyor olabilir.</td></tr><tr><td>Address dili yanlış</td><td>IP geolocation language ve bu dili destekleyen kaynak yapılandırılıp yapılandırılmadığını kontrol edin.</td></tr><tr><td>Address data center gösteriyor</td><td>Birçok proxy, cloud server ve crawler data center veya ISP adresi gibi görünür.</td></tr><tr><td>Upload count yüksek</td><td>Bu IP&#39;yi dikkatle inceleyin ve gerekirse yüklemeleri engelleyin.</td></tr><tr><td>Total upload size büyük</td><td>Sıralayın veya filtreleyin, IP&#39;yi genişletip belirli dosyaları inceleyin.</td></tr><tr><td>Engelleme sonrası geri açmak gerekiyor</td><td><code>Upload allowed</code> değerini yeniden açın.</td></tr></tbody></table><h2 id="kısa-akıs" tabindex="-1">Kısa Akış <a class="header-anchor" href="#kısa-akıs" aria-label="Permalink to &quot;Kısa Akış&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Other Settings içinde IP Geolocation aç</span></span>
<span class="line"><span>-&gt; IP geolocation language seç</span></span>
<span class="line"><span>-&gt; Gerektiği kadar MaxMind, Tencent Map veya ipapi credentials gir</span></span>
<span class="line"><span>-&gt; Ayarları kaydet</span></span>
<span class="line"><span>-&gt; User Management aç</span></span>
<span class="line"><span>-&gt; IP source, address, total upload size ve upload count incele</span></span>
<span class="line"><span>-&gt; Anormal IP&#39;leri bulmak için search, sort veya advanced filters kullan</span></span>
<span class="line"><span>-&gt; Gerektiğinde yüklemelere izin ver veya engelle</span></span></code></pre></div>`,64)])])}const I=d(u,[["render",m]]);export{P as __pageData,I as default};
